import 'dart:io'; void main() { final dir = Directory('lib'); List<File> allFiles = dir.listSync(recursive: true).whereType<File>().where((f) => f.path.endsWith('.dart')).toList(); Map<String, int> importCounts = {}; for (var file in allFiles) { importCounts[file.path] = 0; } for (var file in allFiles) { String content = file.readAsStringSync(); for (var target in allFiles) { if (file.path == target.path) continue; String targetName = target.path.replaceAll('\\\\', '/').replaceFirst('lib/', ''); if (content.contains(targetName) || content.contains(target.path.split('\\\\').last)) { importCounts[target.path] = (importCounts[target.path] ?? 0) + 1; } } } print('Unused files:'); for (var file in allFiles) { if (importCounts[file.path] == 0 && !file.path.contains('main.dart')) { print(file.path); } } }
